{
  "mode": "io",
  "tests": [
    {
      "name": "get_project_members_success",
      "input": "{\"projectId\": \"123\"}",
      "output": "[{\"id\": \"1\", \"name\": \"Alice\", \"role\": \"developer\"}, {\"id\": \"2\", \"name\": \"Bob\", \"role\": \"manager\"}]",
      "notes": "Validates retrieval of project members."
    },
    {
      "name": "post_project_member_success",
      "input": "{\"projectId\": \"123\", \"member\": {\"name\": \"Charlie\", \"role\": \"designer\"}}",
      "output": "{\"id\": \"3\", \"name\": \"Charlie\", \"role\": \"designer\"}",
      "notes": "Validates successful addition of a new member."
    },
    {
      "name": "get_project_invites_success",
      "input": "{\"projectId\": \"123\"}",
      "output": "[{\"inviteId\": \"1\", \"email\": \"invitee@example.com\", \"status\": \"pending\"}]",
      "notes": "Validates retrieval of project invites."
    },
    {
      "name": "post_project_invite_success",
      "input": "{\"projectId\": \"123\", \"invite\": {\"email\": \"newinvitee@example.com\"}}",
      "output": "{\"inviteId\": \"2\", \"email\": \"newinvitee@example.com\", \"status\": \"pending\"}",
      "notes": "Validates successful creation of a new invite."
    },
    {
      "name": "patch_project_member_not_found",
      "input": "{\"projectId\": \"123\", \"id\": \"999\", \"member\": {\"role\": \"admin\"}}",
      "output": "{\"error\": \"Member not found\"}",
      "notes": "Validates error handling for updating a non-existent member."
    },
    {
      "name": "delete_project_member_success",
      "input": "{\"projectId\": \"123\", \"id\": \"1\"}",
      "output": "{\"message\": \"Member removed successfully\"}",
      "notes": "Validates successful deletion of a member."
    },
    {
      "name": "get_project_invite_not_found",
      "input": "{\"projectId\": \"123\", \"inviteId\": \"999\"}",
      "output": "{\"error\": \"Invite not found\"}",
      "notes": "Validates error handling for retrieving a non-existent invite."
    },
    {
      "name": "post_project_invite_duplicate",
      "input": "{\"projectId\": \"123\", \"invite\": {\"email\": \"invitee@example.com\"}}",
      "output": "{\"error\": \"Invite already exists\"}",
      "notes": "Validates error handling for duplicate invites."
    }
  ],
  "assumptions": "Project ID and member IDs are valid and exist in the system.",
  "notes": "Ensure to test both success and error scenarios for comprehensive coverage."
}
